SELECT school_count, student_count
FROM school_counts
WHERE authority_id = 0;

SELECT COUNT(*) AS total_entries, MAX(entry_date) AS latest_entry_date
FROM data_entry_logs
WHERE user_id = 0;

SELECT authority_name
FROM authorities
WHERE ons_code = 'E06000001';

SELECT SUM(school_count) AS total_schools
FROM school_counts
WHERE authority_id = 1;

SELECT MAX(school_count) AS max_school_count
FROM school_counts
WHERE year_id = 1;

SELECT SUM(school_count) AS total_schools
FROM school_counts
WHERE year_id = (SELECT year_id FROM academic_years WHERE year_name = '2005/06');

SELECT authority_id, AVG(student_count) AS average_student_count
FROM school_counts
GROUP BY authority_id;

SELECT authority_name
FROM authorities
ORDER BY authority_name;

SELECT authority_name, population
FROM authorities
ORDER BY population DESC;

SELECT SUM(school_count) AS total_schools, SUM(student_count) AS total_students
FROM school_counts
WHERE authority_id = 1 AND year_id = 0;

SELECT authority_name, population
FROM authorities
WHERE population = (SELECT MAX(population) FROM authorities);

SELECT authority_name 
FROM authorities 
ORDER BY authority_name ASC;

SELECT authority_name
FROM authorities
WHERE authority_id = 0;
